// Report what the upload actually contained, so you can confirm from the
// HTTP response that the file arrived (and is stored with the execution).
const item = $input.first();
const bin = item.binary || {};
const files = Object.entries(bin).map(([key, v]) => ({
  key,
  fileName: v.fileName,
  mimeType: v.mimeType,
  fileExtension: v.fileExtension,
  fileSizeBytes: v.fileSize,
}));
return [{ json: { ok: true, receivedFiles: files.length, files } }];
